impl ArchInterface for ArchInterfaceImpl {
    /// Init allocator
    fn init_allocator(){
        mm::init_heap();
    }
    /// kernel interrupt
    fn kernel_interrupt(ctx: &mut TrapFrame, trap_type: TrapType){
        // println!("trap_type @ {:x?} {:#x?}", trap_type, ctx);
//        let curtask = current_task();
        if let Some(task) = current_task(){
            task.inner_exclusive_access().tms.update_utime();
            task.check_itimer();
        }
//        if curtask.is_some(){
//            curtask.clone().unwrap().inner_exclusive_access().tms.update_utime();
//        }               
//        if curtask.is_some(){
//            curtask.unwrap().check_itimer();
//        }
        match trap_type {
            Breakpoint => return,
            UserEnvCall => {
                // jump to next instruction anyway
                ctx.syscall_ok();
                let args = ctx.args();
                // get system call return value
                // info!("syscall: {}", ctx[TrapFrameArgs::SYSCALL]);
                let id = ctx[TrapFrameArgs::SYSCALL];
                let result = syscall(ctx[TrapFrameArgs::SYSCALL], [args[0], args[1], args[2],args[3],args[4],args[5]]);
                // cx is changed during sys_exec, so we have to call it again
                if id != 93 && id != 139{//exec sigreturn don't return
                    ctx[TrapFrameArgs::RET] = result as usize;//exec中这一句会干死glibc的动态链接器
                }
            }
            StorePageFault(_paddr) | LoadPageFault(_paddr) | InstructionPageFault(_paddr) => {
                let ctask = match current_task() {
                    Some(t) => t,
                    None => {
                        panic!(
                            "page fault during kernel init: {:x?} at sepc:{:x}, no task available to handle it",
                            trap_type, ctx[TrapFrameArgs::SEPC]
                        );
                    }
                };
              //  println!("pgfault addr:{:x} tid:{}",_paddr,ctask.gettid());
              //  println!("trap_type @ {:x?} {:#x?}", trap_type, ctx);
                let inner = ctask.inner_exclusive_access();
                let mut memory_set = inner.memory_set.lock();
                if memory_set.handle_lazy_addr(_paddr, trap_type).is_err() {
                    match trap_type {
                        StorePageFault(_paddr)=>{
                            let r = memory_set.handle_cow_addr(_paddr);
                            if r.is_err(){
                         //       memory_set.debug_addr_info();
                                println!("err {:x?},sepc:{:x},sepcpage:{:x} id:{}", trap_type,ctx[TrapFrameArgs::SEPC],ctx[TrapFrameArgs::SEPC]/PAGE_SIZE,ctask.gettid());
                                //      ctx.syscall_ok();
                                memory_set.debug_addr_info();
                                drop(memory_set);
                                drop(inner);
                                drop(ctask);
                                exit_current_and_run_next(-1);
                            }
                        }
                        _ =>{
                            println!("err {:x?},sepc:{:x},sepcpage:{:x} id:{}", trap_type,ctx[TrapFrameArgs::SEPC],ctx[TrapFrameArgs::SEPC]/PAGE_SIZE,ctask.gettid());
                            //      ctx.syscall_ok();
                            memory_set.debug_addr_info();
                            drop(memory_set);
                            drop(inner);
                            drop(ctask);
                            exit_current_and_run_next(-1);
                        }
                    }

                }
            }
            IllegalInstruction(_) => {
                println!("IllegalInstruction!");
                exit_current_and_run_next(-1);
            }
            Time => {   
               // let curtask = current_task();

                timer::check_futex_timer();
                suspend_current_and_run_next();
            }
            _ => {
           //     println!("unsuspended trap type: {:?}", trap_type);
            }
        }
        crate::task::handle_signals();
        /* 
        let curtask = current_task();
        if curtask.is_some(){
            curtask.unwrap().inner_exclusive_access().tms.update_stime();
        } */
        if let Some(task) = current_task(){
            task.inner_exclusive_access().tms.update_stime();
        }
    }
    /// init log
    fn init_logging(){
        logger::init_logger();
    }
    /// add a memory region
    fn add_memory_region(start: usize, end: usize){
        mm::init_frame_allocator(start, end);
    }
    /// kernel main function, entry point.
    fn main(hartid: usize){
        if hartid != 0 {
