global_asm!(
    r"
    .altmacro
    .macro LOAD reg, offset
        ld  \reg, \offset*8(sp)
    .endm

    .macro SAVE reg, offset
        sd  \reg, \offset*8(sp)
    .endm

    .macro LOAD_N n
        ld  x\n, \n*8(sp)
    .endm

    .macro SAVE_N n
        sd  x\n, \n*8(sp)
    .endm

    .macro SAVE_GENERAL_REGS
        SAVE    x1, 1
        csrr    x1, sscratch
        SAVE    x1, 2
        .set    n, 3
        .rept   29 
            SAVE_N  %n
        .set    n, n + 1
        .endr

        csrr    t0, sstatus
        csrr    t1, sepc
        SAVE    t0, 32
        SAVE    t1, 33
    .endm

    .macro LOAD_GENERAL_REGS
        LOAD    t0, 32
        LOAD    t1, 33
        csrw    sstatus, t0
        csrw    sepc, t1

        LOAD    x1, 1
        .set    n, 3
        .rept   29
            LOAD_N  %n
        .set    n, n + 1
        .endr
        LOAD    x2, 2
    .endm

    .macro LOAD_PERCPU dst, sym
        lui  \dst, %hi(__PERCPU_\sym)
        add  \dst, \dst, gp
        ld   \dst, %lo(__PERCPU_\sym)(\dst)
    .endm

    .macro SAVE_PERCPU sym, temp, src
        lui  \temp, %hi(__PERCPU_\sym)
        add  \temp, \temp, gp
        sd   \src,  %lo(__PERCPU_\sym)(\temp)
    .endm
"
);

