pub fn sys_bind(socket_fd: usize,addr_ptr: *const SocketAddrIn,_address_len: usize,) -> SysResult<isize> {
    let token = current_user_token();
    let task = current_task().unwrap();
    let inner = task.inner_exclusive_access();
    let mut fd_table = inner.fd_table.lock();
    let socket_addr = translated_ref(token, addr_ptr);
    let socket = fd_table.get_file(socket_fd)?.downcast_arc::<Socket>().map_err(|_| SysError::EINVAL)?;
    //println!("sys_bind sockfd:{} addr:{} port:{} tid:{}",socket_fd,socket_addr.addr,socket_addr.in_port.to_be(),task.gettid());
    let net_server = NET_SERVER.clone();
    let port = socket_addr.in_port.to_be();

    if socket_addr.family != 0x02 {
        //warn!("only support IPV4 now");
        return Err(SysError::EAFNOSUPPORT);
    }

    match socket.net_type {
        NetType::STEAM => {
            if net_server.tcp_is_used(port) {
                let sock = socket.reuse(port);
                fd_table.set_fd(socket_fd, Some(Fd::new(Arc::new(sock), FdFlags::empty())));
                return Ok(0);
            }
        }
        NetType::DGRAME => {
            if net_server.udp_is_used(port) {
                let sock = socket.reuse(port);
                fd_table.set_fd(socket_fd, Some(Fd::new(Arc::new(sock), FdFlags::empty())));
                return Ok(0);
            }
        }
        NetType::RAW => {}
    }

    let local = SocketAddrV4::new(socket_addr.addr, port);
    socket
        .inner
        .clone()
        .bind(local)
        .map_err(|_| SysError::EALREADY)?;
    //println!("sys_bindres  sockfd:{} addr:{} port:{} tid:{}",socket_fd,socket.inner.get_local().unwrap().ip(),socket.inner.get_local().unwrap().port(),task.gettid());
    Ok(0)
