impl TCBITimer{
    pub fn new()->Self{
        Self{
            itimer:ITimerVal::new(),
            start_time:TimeVal::new(0, 0),
            is_once:false,
            sig:SignalFlags::empty()
        }
    }
    pub fn set_itimer(&mut self,itimer:ITimerVal){
        self.itimer = itimer;
    }
    pub fn get_itimer(&self)->ITimerVal{
        self.itimer
    }
    pub fn set_start_time(&mut self,start_time:TimeVal){
        self.start_time = start_time;
    }
    pub fn set_is_once(&mut self,is_once:bool){
        self.is_once = is_once;
    }
    pub fn set_sig(&mut self,sig:SignalFlags){
        self.sig = sig;
    }
    pub fn check_itimer(&mut self)->SignalFlags{
        let curtime = get_curtime_val();
      //  if self.itimer.it_value.to_usec() != 0{
       //     println!("checkitimer {} {}",curtime.to_usec(),self.start_time.to_usec() + self.itimer.it_value.to_usec());
       // }
        if self.is_once{
            if curtime > self.start_time + self.itimer.it_value{
                self.set_is_once(false);
                self.set_start_time(curtime);
              //  println!("return sig! {:x}",self.sig.bits());
                return self.sig;
            }
        }
        else if !self.itimer.it_interval.is_zero() {
            if curtime > self.start_time + self.itimer.it_interval {
                self.set_start_time(curtime);
                return self.sig;
            }
        }
        return SignalFlags::empty();
    }
}

