lazy_static! {
    ///
    pub static ref IPCIDS: Mutex<IpcIds> = Mutex::new(IpcIds::new());
}

pub struct IpcIds {
    seq_max: usize,//用于生成shm id(也就是key)
    map: BTreeMap<usize, ShmidKernel>,
}

impl IpcIds{
    pub fn new()->Self{
        Self{
            seq_max:1,
            map:BTreeMap::new()
        }
    }
    pub fn shm_get(&mut self,size:usize)->usize{ // create shm
        let num = (size + PAGE_SIZE - 1) / PAGE_SIZE;
        self.map.insert(self.seq_max, ShmidKernel::new(num));
        let ret = self.seq_max;
        self.seq_max += 1;
        ret
    }
    pub fn shm_exists(&self,key:usize)->bool{
        self.map.get(&key).is_some()
    }
    pub fn shm_ctl(&mut self,key:usize){
        self.map.remove(&key);
    }
}

pub fn shm_get(size:usize)->usize{
    IPCIDS.lock().shm_get(size)
}

pub fn shm_exists(key:usize)->bool{
    IPCIDS.lock().shm_exists(key)
}

pub fn shm_ctl(key:usize){
    IPCIDS.lock().shm_ctl(key);
}

pub fn shm_at(key: usize, addr: usize, map_perm: MapPermission) -> SysResult<isize> {
    let ipcids = IPCIDS.lock();
    if let Some(shm) = ipcids.map.get(&key) {
        let task = current_task().unwrap();
        let inner = task.inner_exclusive_access();
        let mut memory_set = inner.memory_set.lock();
        let size = shm.data_frames.len() * PAGE_SIZE;
        memory_set.add_shm_area(addr, size, map_perm, shm.data_frames.clone())
    } else {
        Err(system_result::SysError::EINVAL)
    }
}

