#[derive(Clone)]
pub struct Fd {
    flags: FdFlags,
    file: Arc<dyn File + Send + Sync>,
}
impl Fd{
    pub fn new(file:Arc<dyn File + Send + Sync>,flags:FdFlags)->Self{
        Self{
            flags,file
        }
    }
