impl Drop for Fd{
    fn drop(&mut self) {
        let dentry = self.file.get_dentry();
        if let Some(father) = dentry.get_father(){
            if father.path() == "/tmp"{
                if father.lookup(dentry.get_name_str()).is_ok(){
                    return;
                }
                if Arc::strong_count(&self.file) > 1{
                    return;
                }
                if let Some(arc_self) = vfs::get_vfs_dentry(dentry.path()){
                    drop(dentry);
                    arc_self.get_inode().unwrap().clear();
                }
            }
        }
    }
}

