pub const EPOLLPRI: u32 = 0x002;
pub const EPOLLOUT: u32 = 0x004;
pub const EPOLLERR: u32 = 0x008;
pub const EPOLLHUP: u32 = 0x010;
pub const EPOLLRDHUP: u32 = 0x2000;

/// Entry in the epoll interest list
struct EpollEntry {
    #[allow(unused)]
    fd: i32,
    event: EpollEvent,
}

pub struct EpollFile {
    /// Interest list: monitored fd → EpollEvent
    interests: Mutex<BTreeMap<i32, EpollEntry>>,
    #[allow(unused)]
    epoll_flags: Mutex<i32>,
    inner: FileInner,
}

impl EpollFile {
    pub fn new(inner: FileInner, flags: i32) -> Self {
        Self { interests: Mutex::new(BTreeMap::new()), epoll_flags: Mutex::new(flags), inner }
    }
}

impl File for EpollFile {
    fn get_inner(&self) -> &FileInner { &self.inner }
    fn readable(&self) -> bool { true }
    fn writable(&self) -> bool { false }

    fn read_at(&self, _offset: usize, _buf: &mut [u8]) -> usize { 0 }
    fn write_at(&self, _offset: usize, _buf: &[u8]) -> usize { 0 }
    fn read(&self, _buf: &mut [u8]) -> usize { 0 }
    fn write(&self, _buf: &[u8]) -> usize { 0 }

    fn poll(&self, events: PollEvents) -> PollEvents {
        if !events.contains(PollEvents::POLLIN) { return PollEvents::empty(); }
        let interests = self.interests.lock();
        if interests.is_empty() { return PollEvents::empty(); }
        let task = current_task().unwrap();
        let inner = task.inner_exclusive_access();
        let fd_table = inner.fd_table.lock();
        for (_fd, entry) in interests.iter() {
            if let Ok(file) = fd_table.get_file(*_fd as usize) {
                let ready = file.poll(PollEvents::from_bits_truncate(entry.event.events as i16));
                if !ready.is_empty() {
                    return PollEvents::POLLIN;
                }
            }
        }

